@final
def _aggregate_series_fast(
    self, obj: Series, func: Callable
) -> npt.NDArray[np.object_]:
    """
    Faster aggregation using direct label indexing instead of creating sorted groups.
    Avoids the overhead of DataSplitter sorting and Series object creation.
    """
    result = np.empty(self.ngroups, dtype="O")
    initialized = False
    ids = self.ids

    # Accumulate indices for each group label
    group_indices: dict[int, list[int]] = {}
    for label_id in range(self.ngroups):
        group_indices[label_id] = []

    # Collect indices for each group (skip NA labels)
    for i, label_id in enumerate(ids):
        if label_id >= 0:
            group_indices[label_id].append(i)

    # Apply function to each group
    for label_id in range(self.ngroups):
        indices = group_indices[label_id]
        if indices:
            # Use iloc to create group without sorting/copying
            group = obj.iloc[indices]
        else:
            # Empty group - create empty Series with same dtype
            group = obj.iloc[:0]

        res = func(group)
        res = extract_result(res)

        if not initialized:
            # We only do this validation on the first iteration
            check_result_array(res, obj.dtype)
            initialized = True

        result[label_id] = res

    return result

